import xml.etree.ElementTree as ET

def validate_xml(xml_string):
    try:
        root = ET.fromstring(xml_string)
        if root.tag != 'root':
            return False
        for child in root:
            if child.tag not in ['name', 'age']:
                return False
            if child.tag == 'name' and not isinstance(child.text, str):
                return False
            if child.tag == 'age' and not isinstance(child.text, int):
                return False
    except ET.ParseError:
        return False
    return True

def read_xml(xml_string):
    try:
        root = ET.fromstring(xml_string)
        data = {}
        for child in root:
            data[child.tag] = child.text
        return data
    except ET.ParseError:
        return None